class Solution:
    def makeSmallestPalindrome(self, s: str) -> str:
        s = list(s)
        n = len(s)
        for i in range(n // 2):
            j = n - 1 - i
            if s[i] != s[j]:
                # Replace both with the smaller character
                smaller_char = min(s[i], s[j])
                s[i] = smaller_char
                s[j] = smaller_char
        return ''.join(s)
